#!/usr/bin/env python3
import rclpy
from rclpy.node import Node
from geometry_msgs.msg import Twist
from std_msgs.msg import String
from action_msgs.srv import CancelGoal
import sys
import termios
import tty
import threading
import time

class ModeSwitchNode(Node):
    def __init__(self):
        super().__init__('mode_switch_node')

        # 모드: 'manual' or 'auto'
        self.mode = 'manual'

        # 자율주행 속도 (safety_stop_node에서 필터링된 최종 명령)
        self.nav_cmd_sub = self.create_subscription(
            Twist, '/cmd_vel_safe', self.nav_cmd_callback, 10)

        # 수동 조작 속도 (teleop_keyboard)
        self.teleop_cmd_sub = self.create_subscription(
            Twist, '/cmd_vel_teleop', self.teleop_cmd_callback, 10)

        # 최종 출력
        self.cmd_pub = self.create_publisher(Twist, '/cmd_vel', 10)

        # 모드 상태 발행 (웹 UI 연동용)
        self.mode_pub = self.create_publisher(String, '/robot_mode', 10)

        # 마지막 teleop 수신 시간
        self.last_teleop_time = 0.0

        # 주기적 발행 타이머 (10Hz)
        self.create_timer(0.1, self.control_loop)

        # 모드 상태 주기적 발행
        self.create_timer(1.0, self.publish_mode)

        # 최신 명령 저장
        self.latest_nav_cmd = Twist()
        self.latest_teleop_cmd = Twist()

        # 키보드 입력 쓰레드
        self.key_thread = threading.Thread(target=self.key_listener, daemon=True)
        self.key_thread.start()
        self.nav_cancel_client = self.create_client(CancelGoal, '/navigate_to_pose/_action/cancel_goal')
        self.get_logger().info(
            f'Mode Switch Node 시작 - 현재 모드: {self.mode}\n'
            f'  [자율] /cmd_vel_safe → /cmd_vel\n'
            f'  [수동] /cmd_vel_teleop → /cmd_vel\n'
            f'  [m] 모드 전환 (일시정지/재개)  [q] 종료')

    def nav_cmd_callback(self, msg):
        """자율주행 명령 저장"""
        self.latest_nav_cmd = msg

    def teleop_cmd_callback(self, msg):
        """수동 조작 명령 저장"""
        self.latest_teleop_cmd = msg
        self.last_teleop_time = time.time()

    def control_loop(self):
        """10Hz로 현재 모드에 맞는 명령을 발행"""
        if self.mode == 'auto':
            self.cmd_pub.publish(self.latest_nav_cmd)
        else:
            # 수동 모드: teleop 입력이 0.5초 이내면 전달, 아니면 정지
            if time.time() - self.last_teleop_time < 0.5:
                self.cmd_pub.publish(self.latest_teleop_cmd)
            else:
                stop_cmd = Twist()
                self.cmd_pub.publish(stop_cmd)

    def publish_mode(self):
        """현재 모드 상태 발행"""
        mode_msg = String()
        mode_msg.data = self.mode
        self.mode_pub.publish(mode_msg)

    def switch_mode(self):
        """모드 전환"""
        # 즉시 정지
        stop_cmd = Twist()
        self.cmd_pub.publish(stop_cmd)

        # 저장된 명령 초기화
        self.latest_nav_cmd = Twist()
        self.latest_teleop_cmd = Twist()

        if self.mode == 'manual':
            self.mode = 'auto'
            self.get_logger().info('>>> 자율주행 모드로 전환 (새로운 목적지를 입력하세요)')
        else:
            self.mode = 'manual'
            self.get_logger().info('>>> 수동 조작 모드로 전환 (Nav2 자율주행 강제 취소)')
            self.cancel_nav2_goal()  # <--- 수동 모드가 되면 취소 함수 실행

    def cancel_nav2_goal(self):
        """Nav2 Action Server에 모든 목표 취소 요청"""
        if self.nav_cancel_client.wait_for_service(timeout_sec=0.5):
            req = CancelGoal.Request()
            # 빈 Request를 보내면 활성화된 Nav2 Goal을 즉각 취소합니다.
            self.nav_cancel_client.call_async(req)
            self.get_logger().info('Nav2 목적지(Goal)가 성공적으로 취소되었습니다.')
        else:
            self.get_logger().warn('Nav2 취소 서비스를 찾을 수 없습니다. (Nav2가 실행 중인지 확인)')
    def key_listener(self):
        """키보드 입력 감지 (별도 쓰레드)"""
        old_settings = termios.tcgetattr(sys.stdin)
        try:
            tty.setraw(sys.stdin.fileno())
            while rclpy.ok():
                key = sys.stdin.read(1)
                if key == 'm' or key == 'M':
                    self.switch_mode()
                elif key == 'q' or key == 'Q':
                    self.get_logger().info('종료합니다.')
                    rclpy.shutdown()
                    break
        finally:
            termios.tcsetattr(sys.stdin, termios.TCSADRAIN, old_settings)


def main(args=None):
    rclpy.init(args=args)
    node = ModeSwitchNode()
    try:
        rclpy.spin(node)
    except KeyboardInterrupt:
        pass
    finally:
        node.destroy_node()
        rclpy.shutdown()

if __name__ == '__main__':
    main()